export type SeoLocale = keyof typeof SEO_TRANSLATIONS;

export type SeoStrings = (typeof SEO_TRANSLATIONS)[SeoLocale];

export function getSeoStrings(locale: string): SeoStrings {
  if (locale in SEO_TRANSLATIONS) {
    return SEO_TRANSLATIONS[locale as SeoLocale];
  }
  return SEO_TRANSLATIONS.en;
}
